import{_ as a,o as s,c as n,a2 as i}from"./chunks/framework.OWFDNrRT.js";const h=JSON.parse('{"title":"Asset Intake PRD (assetctl)","description":"","frontmatter":{},"headers":[],"relativePath":"asset-intake/assetctl-prd.md","filePath":"asset-intake/assetctl-prd.md","lastUpdated":1773460793000}'),l={name:"asset-intake/assetctl-prd.md"};function o(t,e,c,r,d,p){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="asset-intake-prd-assetctl" tabindex="-1">Asset Intake PRD (<code>assetctl</code>) <a class="header-anchor" href="#asset-intake-prd-assetctl" aria-label="Permalink to &quot;Asset Intake PRD (\`assetctl\`)&quot;">​</a></h1><p><strong>Version</strong>: 0.1.0<br><strong>Status</strong>: Draft<br><strong>Owner</strong>: docs/warfare-designer (pre-impl domain owner)<br><strong>Created</strong>: 2026-03-11</p><h2 id="_1-purpose" tabindex="-1">1. Purpose <a class="header-anchor" href="#_1-purpose" aria-label="Permalink to &quot;1. Purpose&quot;">​</a></h2><p>Build a deterministic, machine-driven intake pipeline for Star-Wars-style prototype assets that keeps technical viability and IP provenance separate.</p><p>The PRD scope is pre-implementation planning for a CLI-first tool chain and required data contracts; no runtime pack application logic is included in this phase.</p><h2 id="_2-non-goals" tabindex="-1">2. Non-Goals <a class="header-anchor" href="#_2-non-goals" aria-label="Permalink to &quot;2. Non-Goals&quot;">​</a></h2><ul><li>No legal claims about public Star Wars compatibility.</li><li>No full Unity asset optimization tooling in V1.</li><li>No marketplace publishing or distribution controls in V1.</li><li>No automatic source-specific scraping for every site.</li></ul><h2 id="_3-design-goals" tabindex="-1">3. Design Goals <a class="header-anchor" href="#_3-design-goals" aria-label="Permalink to &quot;3. Design Goals&quot;">​</a></h2><ul><li>Machine-friendly discovery first (API over scrape over browser automation).</li><li>Strict manifest-first asset lifecycle.</li><li>Explicit provenance state machine.</li><li>Shared risk and quality gates across agents and runs.</li><li>Reproducible directory and file naming conventions.</li></ul><h2 id="_4-directory-model" tabindex="-1">4. Directory Model <a class="header-anchor" href="#_4-directory-model" aria-label="Permalink to &quot;4. Directory Model&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/assets-pipeline</span></span>
<span class="line"><span>  /sources</span></span>
<span class="line"><span>    /sketchfab</span></span>
<span class="line"><span>    /blendswap</span></span>
<span class="line"><span>    /moddb</span></span>
<span class="line"><span>  /registry</span></span>
<span class="line"><span>    asset_index.json</span></span>
<span class="line"><span>    provenance_index.json</span></span>
<span class="line"><span>  /raw</span></span>
<span class="line"><span>    /sw_b1_droid_sketchfab_001</span></span>
<span class="line"><span>      source_download.glb</span></span>
<span class="line"><span>      metadata.json</span></span>
<span class="line"><span>      asset_manifest.json</span></span>
<span class="line"><span>  /working</span></span>
<span class="line"><span>    /sw_b1_droid_sketchfab_001</span></span>
<span class="line"><span>      normalized.blend</span></span>
<span class="line"><span>      normalized.glb</span></span>
<span class="line"><span>      preview.png</span></span>
<span class="line"><span>      validation_report.json</span></span>
<span class="line"><span>  /export</span></span>
<span class="line"><span>    /unity</span></span>
<span class="line"><span>      /units</span></span>
<span class="line"><span>      /vehicles</span></span>
<span class="line"><span>      /props</span></span>
<span class="line"><span>  /logs</span></span></code></pre></div><h2 id="_5-core-cli-contract" tabindex="-1">5. Core CLI Contract <a class="header-anchor" href="#_5-core-cli-contract" aria-label="Permalink to &quot;5. Core CLI Contract&quot;">​</a></h2><p><code>assetctl</code> is organized around a single noun and explicit lifecycle verbs.</p><ul><li><code>assetctl search --source &lt;tier&gt; &quot;&lt;query&gt;&quot; [--limit N]</code></li><li><code>assetctl intake &lt;candidate_ref&gt;</code></li><li><code>assetctl normalize &lt;asset_id&gt;</code></li><li><code>assetctl validate &lt;asset_id&gt;</code></li><li><code>assetctl stylize &lt;asset_id&gt; --profile dinosw_lowpoly_v1</code></li><li><code>assetctl register &lt;asset_id&gt;</code></li><li><code>assetctl export-unity &lt;asset_id&gt; [--bundle unit|vehicle|prop]</code></li></ul><p>All commands output JSON by default when <code>--format json</code> is set.<br> Machine parsing must not depend on colored terminal output.</p><h2 id="_6-source-adapter-model" tabindex="-1">6. Source Adapter Model <a class="header-anchor" href="#_6-source-adapter-model" aria-label="Permalink to &quot;6. Source Adapter Model&quot;">​</a></h2><p>All source adapters implement a common contract:</p><ul><li><code>source_name()</code></li><li><code>search(query, filters) -&gt; candidates</code></li><li><code>fetch_metadata(external_id)</code></li><li><code>can_download(external_id) -&gt; bool</code></li><li><code>download(external_id, out_dir) -&gt; file list</code></li><li><code>estimate_poly_and_style_score(candidate) -&gt; score metadata</code></li></ul><p>Planned adapters:</p><ul><li><code>SketchfabAdapter</code> (API-first, GLB/GTLF/USdz output).</li><li><code>BlendSwapAdapter</code> (scrape-assisted with cache of downloaded assets).</li><li><code>ModDbAdapter</code> (reference-only legacy source).</li><li><code>PlaywrightFallbackAdapter</code> (manual pages only).</li></ul><h2 id="_7-candidate-lifecycle" tabindex="-1">7. Candidate Lifecycle <a class="header-anchor" href="#_7-candidate-lifecycle" aria-label="Permalink to &quot;7. Candidate Lifecycle&quot;">​</a></h2><p>Technical and IP state are independent:</p><ul><li>Technical: <code>discovered</code>, <code>metadata_fetched</code>, <code>downloadable</code>, <code>downloaded</code>, <code>normalized</code>, <code>validated</code>, <code>ready_for_prototype</code>, <code>rejected_technical</code>.</li><li>IP: <code>generic_safe</code>, <code>fan_star_wars_private_only</code>, <code>official_game_mod_tool_reference_only</code>, <code>unknown_provenance</code>, <code>high_risk_do_not_ship</code>.</li></ul><p>An asset may progress technical stages while remaining blocked by IP state.</p><h2 id="_8-scoring-model" tabindex="-1">8. Scoring Model <a class="header-anchor" href="#_8-scoring-model" aria-label="Permalink to &quot;8. Scoring Model&quot;">​</a></h2><p>Suggested initial ranking:</p><p><code>0.30*style_fit + 0.20*faction_fit + 0.15*automation_ease + 0.10*topology_quality + 0.10*low_poly_fit + 0.10*provenance_confidence - 0.15*ip_risk_penalty - 0.10*cleanup_cost</code></p><p>Score thresholds are enforced by policy and can be tuned in <code>manifests/asset-intake/source-rules.yaml</code>.</p><h2 id="_9-policy-and-data-contracts" tabindex="-1">9. Policy and Data Contracts <a class="header-anchor" href="#_9-policy-and-data-contracts" aria-label="Permalink to &quot;9. Policy and Data Contracts&quot;">​</a></h2><ul><li>Manifest schema: <code>schemas/asset-manifest.schema.json</code></li><li>Source/risk policy: <code>manifests/asset-intake/source-rules.yaml</code></li><li>Validation report schema: defined in normalization worker and Unity export outputs.</li></ul><h2 id="_10-v1-scope-pre-impl-slice" tabindex="-1">10. V1 Scope (Pre-Impl Slice) <a class="header-anchor" href="#_10-v1-scope-pre-impl-slice" aria-label="Permalink to &quot;10. V1 Scope (Pre-Impl Slice)&quot;">​</a></h2><ul><li>Source support: Sketchfab only</li><li>Candidate classes: <ul><li>clone trooper</li><li>B1 battle droid</li><li>stormtrooper</li><li>TIE fighter</li><li>X-wing</li><li>AAT tank</li><li>desert / outer-rim structure props</li></ul></li><li>Outputs: <ul><li>manifest</li><li>raw download</li><li>normalized GLB</li><li>preview</li><li>validation report</li></ul></li></ul><h2 id="_11-open-decisions" tabindex="-1">11. Open Decisions <a class="header-anchor" href="#_11-open-decisions" aria-label="Permalink to &quot;11. Open Decisions&quot;">​</a></h2><ul><li>Whether to add an offline mirror cache for downloaded zip payloads in V1.</li><li>Whether <code>normalize</code> performs geometry decimation internally or invokes external Blender profiles.</li><li>Whether legal risk overrides are stored per pack or global policy.</li></ul>`,34)])])}const _=a(l,[["render",o]]);export{h as __pageData,_ as default};
